create extension if not exists "uuid-ossp";
create table if not exists facilities(id uuid primary key default uuid_generate_v4(),name text not null,code text unique not null,created_at timestamptz default now());
insert into facilities(name,code) values('Ege Nefes Huzurevi','ege'),('İlgi Huzurevi','ilgi'),('İlgi 2 Huzurevi','ilgi2') on conflict(code) do nothing;
create table if not exists profiles(id uuid primary key references auth.users(id) on delete cascade,full_name text,role text not null default 'nurse' check(role in('founder','manager','nurse','viewer')),facility_id uuid references facilities(id),created_at timestamptz default now());
create table if not exists patients(id uuid primary key default uuid_generate_v4(),facility_id uuid not null references facilities(id) on delete cascade,full_name text not null,tc_no text,birth_date date,floor_no text,room_no text,bed_no text,alarm_no text,relative_name text,relative_phone text,doctor_name text,allergies text,diagnoses text,status text default 'Aktif',created_at timestamptz default now());
create table if not exists medications(id uuid primary key default uuid_generate_v4(),facility_id uuid not null references facilities(id) on delete cascade,patient_id uuid not null references patients(id) on delete cascade,drug_name text not null,daily_use text default '1x1',stock numeric default 0,min_stock numeric default 10,rx_date date,exp_date date,status text default 'active' check(status in('active','stopped')),created_at timestamptz default now());
create table if not exists medication_movements(id uuid primary key default uuid_generate_v4(),facility_id uuid not null references facilities(id) on delete cascade,patient_id uuid references patients(id) on delete set null,medication_id uuid references medications(id) on delete set null,movement_type text not null,qty numeric default 0,before_stock numeric default 0,after_stock numeric default 0,note text,created_at timestamptz default now());
create table if not exists depot_items(id uuid primary key default uuid_generate_v4(),facility_id uuid not null references facilities(id) on delete cascade,name text not null,barcode text,category text default 'İlaç',shelf text,lot_no text,exp_date date,current_stock numeric default 0,min_stock numeric default 5,max_stock numeric default 20,created_at timestamptz default now());
create table if not exists stock_requests(id uuid primary key default uuid_generate_v4(),facility_id uuid not null references facilities(id) on delete cascade,product_name text not null,category text default 'İlaç',current_stock numeric default 0,requested_qty numeric default 0,min_stock numeric default 0,priority text default 'Normal',status text default 'Bekliyor',approval_status text default 'Bekliyor',source text default 'manual',requested_by uuid references auth.users(id),approved_by uuid references auth.users(id),approved_at timestamptz,created_at timestamptz default now());
create table if not exists deliveries(id uuid primary key default uuid_generate_v4(),facility_id uuid not null references facilities(id) on delete cascade,stock_request_id uuid references stock_requests(id) on delete set null,product_name text not null,qty numeric default 0,lot_no text,exp_date date,shelf text,source text,created_at timestamptz default now());
create table if not exists documents(id uuid primary key default uuid_generate_v4(),facility_id uuid not null references facilities(id) on delete cascade,patient_id uuid references patients(id) on delete cascade,category text not null,title text,storage_path text,note text,created_at timestamptz default now());
create or replace function current_user_role() returns text language sql security definer as $$ select role from profiles where id=auth.uid() $$;
create or replace function current_user_facility() returns uuid language sql security definer as $$ select facility_id from profiles where id=auth.uid() $$;
alter table facilities enable row level security;alter table profiles enable row level security;alter table patients enable row level security;alter table medications enable row level security;alter table medication_movements enable row level security;alter table depot_items enable row level security;alter table stock_requests enable row level security;alter table deliveries enable row level security;alter table documents enable row level security;
drop policy if exists "facilities read" on facilities;create policy "facilities read" on facilities for select to authenticated using(true);
drop policy if exists "profiles read" on profiles;create policy "profiles read" on profiles for select to authenticated using(id=auth.uid() or current_user_role()='founder');
drop policy if exists "profiles founder write" on profiles;create policy "profiles founder write" on profiles for all to authenticated using(current_user_role()='founder') with check(current_user_role()='founder');
drop policy if exists "patients read" on patients;create policy "patients read" on patients for select to authenticated using(current_user_role()='founder' or facility_id=current_user_facility());
drop policy if exists "patients write" on patients;create policy "patients write" on patients for all to authenticated using(current_user_role() in('founder','manager','nurse') and (current_user_role()='founder' or facility_id=current_user_facility())) with check(current_user_role() in('founder','manager','nurse') and (current_user_role()='founder' or facility_id=current_user_facility()));
drop policy if exists "medications read" on medications;create policy "medications read" on medications for select to authenticated using(current_user_role()='founder' or facility_id=current_user_facility());
drop policy if exists "medications write" on medications;create policy "medications write" on medications for all to authenticated using(current_user_role() in('founder','manager','nurse') and (current_user_role()='founder' or facility_id=current_user_facility())) with check(current_user_role() in('founder','manager','nurse') and (current_user_role()='founder' or facility_id=current_user_facility()));
drop policy if exists "movements read" on medication_movements;create policy "movements read" on medication_movements for select to authenticated using(current_user_role()='founder' or facility_id=current_user_facility());
drop policy if exists "movements write" on medication_movements;create policy "movements write" on medication_movements for all to authenticated using(current_user_role() in('founder','manager','nurse') and (current_user_role()='founder' or facility_id=current_user_facility())) with check(current_user_role() in('founder','manager','nurse') and (current_user_role()='founder' or facility_id=current_user_facility()));
drop policy if exists "depot read" on depot_items;create policy "depot read" on depot_items for select to authenticated using(current_user_role()='founder' or facility_id=current_user_facility());
drop policy if exists "depot write" on depot_items;create policy "depot write" on depot_items for all to authenticated using(current_user_role() in('founder','manager','nurse') and (current_user_role()='founder' or facility_id=current_user_facility())) with check(current_user_role() in('founder','manager','nurse') and (current_user_role()='founder' or facility_id=current_user_facility()));
drop policy if exists "requests read" on stock_requests;create policy "requests read" on stock_requests for select to authenticated using(current_user_role()='founder' or facility_id=current_user_facility());
drop policy if exists "requests write" on stock_requests;create policy "requests write" on stock_requests for all to authenticated using(current_user_role() in('founder','manager','nurse') and (current_user_role()='founder' or facility_id=current_user_facility())) with check(current_user_role() in('founder','manager','nurse') and (current_user_role()='founder' or facility_id=current_user_facility()));
drop policy if exists "deliveries read" on deliveries;create policy "deliveries read" on deliveries for select to authenticated using(current_user_role()='founder' or facility_id=current_user_facility());
drop policy if exists "deliveries write" on deliveries;create policy "deliveries write" on deliveries for all to authenticated using(current_user_role() in('founder','manager','nurse') and (current_user_role()='founder' or facility_id=current_user_facility())) with check(current_user_role() in('founder','manager','nurse') and (current_user_role()='founder' or facility_id=current_user_facility()));
drop policy if exists "documents read" on documents;create policy "documents read" on documents for select to authenticated using(current_user_role()='founder' or facility_id=current_user_facility());
drop policy if exists "documents write" on documents;create policy "documents write" on documents for all to authenticated using(current_user_role() in('founder','manager','nurse') and (current_user_role()='founder' or facility_id=current_user_facility())) with check(current_user_role() in('founder','manager','nurse') and (current_user_role()='founder' or facility_id=current_user_facility()));
